import { redirect } from 'react-router-dom';
import AuthForm from '../components/AuthForm';

function AuthenticationPage() {
  return <AuthForm />;
}

export default AuthenticationPage;

export async function action({request}){

  // fro getting hold of the url and get the query parameter we can not use useSearchParams hook because we are not in component we are out side of the component 
  // we will use another in-build feature of browser
  const searchParams = new URL(request.url).searchParams;
  const mode = searchParams.get('mode') || 'login';

  if(mode !== 'login' && mode !== 'signup'){
    throw new Response(JSON.stringify({ message: 'Could not able to login or signup...' }), { status: 422 });
  }

  const data = await request.formData();
  const authData = {
    email : data.get('email'),
    password : data.get('password'),
  }

  const response = await fetch('http://localhost:8080/' + mode ,{
    method : 'POST',
    headers : {
      'Content-Type' : 'application/json',
    },
    body : JSON.stringify(authData),
  });

  if(response.status === 422 || response.status === 401){
    return response;
  }

  if(!response.ok){
    throw new Response(JSON.stringify({ message: 'Could not authenticate user...' }), { status: 500 });
  }

  const resData = await response.json();
  const token = resData.token;
  // now we are sending token after success full login and signup so now we have to store that token in order to give access to the user 
  localStorage.setItem('token' ,token );
  const expiration = new Date();
  expiration.setHours(expiration.get)

  return redirect('/');
}
